pub fn run(vec_dir: &str, out_dir: &str) -> (u32, u32) {
    let mut passed = 0u32;
    let mut failed = 0u32;
    let (p, f) = test_model_opt_inner(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_shape_circle(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_shape_rect(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_ident_name(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_ident_number(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_result_msg_ok(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_result_msg_err(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_tagged_tag(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_tagged_score(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_tagged_active(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_opt_union_holder_shape(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_opt_union_holder_id(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_mixed_union_point(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_mixed_union_label(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_mixed_union_count(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_nested_union_result(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_nested_union_shape(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_scalar_union_s(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_scalar_union_i(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_scalar_union_f(vec_dir, out_dir); passed += p; failed += f;
    let (p, f) = test_model_scalar_union_b(vec_dir, out_dir); passed += p; failed += f;

    (passed, failed)
}
